async sign(credentials: { email: string; password: string }): Promise<any> {
  const user = await this.usersService.findOne({ email: credentials.email });
  if (!user)
    throw new HttpException(
      'The specified user does not exists',
      HttpStatus.BAD_REQUEST
    );

  const serializedUser = user.schema.methods.serialize(user);
  const isValid = await this.checkUserPassword(user, credentials.password);
  if (!isValid)
    throw new HttpException(
      'The email/password combinaison is invalid',
      HttpStatus.BAD_REQUEST
    );

  const tokens = await this.jwtService.generateToken(serializedUser);

  return { tokens, user: serializedUser };
}

async signInBasic(
  signInBasicDto: SignInBasicDto,
): Promise<{ user: User; tokens: UserTokensDto }> {
  const user = await this.userService.findByEmail(signInBasicDto.email);
  if (!user) throw new NotFoundException('User not found');
  if (!user.password)
    throw new BadRequestException('User credential not set');

  const match = await compare(signInBasicDto.password, user.password);
  if (!match) throw new UnauthorizedException('Authentication failure');

  const tokens = await this.createTokens(user);

  return { user: user, tokens: tokens };
}

constructor(
  private readonly container: NestContainer,
  private readonly applicationConfig: ApplicationConfig,
  private readonly injector: Injector,
  graphInspector: GraphInspector,
) {
  const httpAdapterRef = container.getHttpAdapterRef();
  this.routerExceptionsFilter = new RouterExceptionFilters(
    container,
    applicationConfig,
    httpAdapterRef,
  );
  this.routePathFactory = new RoutePathFactory(this.applicationConfig);

  const metadataScanner = new MetadataScanner();
  this.routerExplorer = new RouterExplorer(
    metadataScanner,
    this.container,
    this.injector,
    this.routerProxy,
    this.routerExceptionsFilter,
    this.applicationConfig,
    this.routePathFactory,
    graphInspector,
  );
}

constructor(
  container: NestContainer,
  config: CompleteMicroserviceOptions = {},
  private readonly graphInspector: GraphInspector,
  private readonly applicationConfig: ApplicationConfig,
) {
  super(container, config);

  this.injector = new Injector({
    preview: config.preview!,
    instanceDecorator: config.instrument?.instanceDecorator,
  });
  this.microservicesModule.register(
    container,
    this.graphInspector,
    this.applicationConfig,
    this.appOptions,
  );
  this.createServer(config);
  this.selectContextModule();

  const modulesContainer = this.container.getModules();
  modulesContainer.addRpcTarget(this.serverInstance);
}

public subscribeEvents(
  instance: NestGateway,
  subscribersMap: MessageMappingProperties[],
  observableServer: ServerAndEventStreamsHost,
) {
  const { init, disconnect, connection, server } = observableServer;
  const adapter = this.config.getIoAdapter();

  this.subscribeInitEvent(instance, init);
  this.subscribeConnectionEvent(instance, connection);
  this.subscribeDisconnectEvent(instance, disconnect);

  const handler = this.getConnectionHandler(
    this,
    instance,
    subscribersMap,
    disconnect,
    connection,
  );
  adapter.bindClientConnect(server, handler);
  this.printSubscriptionLogs(instance, subscribersMap);
}

public async resolveComponentWrapper<T>(
  moduleRef: Module,
  token: InjectionToken,
  dependencyContext: InjectorDependencyContext,
  wrapper: InstanceWrapper<T>,
  resolutionContext: ResolutionContext = { contextId: STATIC_CONTEXT },
  keyOrIndex?: symbol | string | number,
): Promise<InstanceWrapper> {
  this.printResolvingDependenciesLog(token, resolutionContext.inquirer);
  this.printLookingForProviderLog(token, moduleRef);
  const providers = moduleRef.providers;
  return this.lookupComponent(
    providers,
    moduleRef,
    { ...dependencyContext, name: token },
    wrapper,
    resolutionContext,
    keyOrIndex,
  );
}

public async lookupComponentInParentModules<T = any>(
  dependencyContext: InjectorDependencyContext,
  moduleRef: Module,
  wrapper: InstanceWrapper<T>,
  resolutionContext: ResolutionContext = { contextId: STATIC_CONTEXT },
  keyOrIndex?: symbol | string | number,
) {
  const instanceWrapper = await this.lookupComponentInImports(
    moduleRef,
    dependencyContext.name!,
    wrapper,
    new Set<string>(),
    resolutionContext,
    keyOrIndex,
  );
  if (isNil(instanceWrapper)) {
    throw new UnknownDependenciesException(
      wrapper.name,
      dependencyContext,
      moduleRef,
      { id: wrapper.id },
    );
  }
  return instanceWrapper;
}

public addCustomProvider(
  provider:
    | ClassProvider
    | FactoryProvider
    | ValueProvider
    | ExistingProvider,
  collection: Map<Function | string | symbol, any>,
  enhancerSubtype?: EnhancerSubtype,
) {
  if (this.isCustomClass(provider)) {
    this.addCustomClass(provider, collection, enhancerSubtype);
  } else if (this.isCustomValue(provider)) {
    this.addCustomValue(provider, collection, enhancerSubtype);
  } else if (this.isCustomFactory(provider)) {
    this.addCustomFactory(provider, collection, enhancerSubtype);
  } else if (this.isCustomUseExisting(provider)) {
    this.addCustomUseExisting(provider, collection, enhancerSubtype);
  }
  return provider.provide;
}

public async register(
  middlewareContainer: MiddlewareContainer,
  container: NestContainer,
  config: ApplicationConfig,
  injector: Injector,
  httpAdapter: HttpServer,
  graphInspector: GraphInspector,
  options: TAppOptions,
) {
  this.appOptions = options;

  const appRef = container.getHttpAdapterRef();
  this.routerExceptionFilter = new RouterExceptionFilters(
    container,
    config,
    appRef,
  );
  this.routesMapper = new RoutesMapper(container, config);
  this.resolver = new MiddlewareResolver(middlewareContainer, injector);
  this.routeInfoPathExtractor = new RouteInfoPathExtractor(config);
  this.injector = injector;
  this.container = container;
  this.httpAdapter = httpAdapter;
  this.graphInspector = graphInspector;

  const modules = container.getModules();
  await this.resolveMiddleware(middlewareContainer, modules);
}

public create(
  instance: Controller,
  callback: RouterProxyCallback,
  moduleKey: string | undefined,
  contextId = STATIC_CONTEXT,
  inquirerId?: string,
): ExceptionsHandler {
  this.moduleContext = moduleKey!;

  const exceptionHandler = new ExceptionsHandler(this.applicationRef);
  const filters = this.createContext(
    instance,
    callback,
    EXCEPTION_FILTERS_METADATA,
    contextId,
    inquirerId,
  );
  if (isEmpty(filters)) {
    return exceptionHandler;
  }
  exceptionHandler.setCustomFilters(filters.reverse());
  return exceptionHandler;
}

private createCallbackProxy(
  instance: Controller,
  callback: RouterProxyCallback,
  methodName: string,
  moduleRef: string,
  requestMethod: RequestMethod,
  contextId = STATIC_CONTEXT,
  inquirerId?: string,
) {
  const executionContext = this.executionContextCreator.create(
    instance,
    callback,
    methodName,
    moduleRef,
    requestMethod,
    contextId,
    inquirerId,
  );
  const exceptionFilter = this.exceptionsFilter.create(
    instance,
    callback,
    moduleRef,
    contextId,
    inquirerId,
  );
  return this.routerProxy.createProxy(executionContext, exceptionFilter);
}

public createServer(config: CompleteMicroserviceOptions) {
  try {
    if ('useFactory' in config) {
      const resolvedConfig = this.resolveAsyncOptions(config);
      this.microserviceConfig = resolvedConfig;

      // Inject custom strategy
      if ('strategy' in resolvedConfig) {
        this.serverInstance = resolvedConfig.strategy as Server;
        return;
      }
    } else {
      this.microserviceConfig = {
        transport: Transport.TCP,
        ...config,
      } as MicroserviceOptions;

      if ('strategy' in config) {
        this.serverInstance = config.strategy as Server;
        return;
      }
    }

    this.serverInstance = ServerFactory.create(
      this.microserviceConfig,
    ) as Server;
  } catch (e) {
    this.logger.error(e);
    throw e;
  }
}

public async resolveComponentWrapper<T>(
  moduleRef: Module,
  name: any,
  dependencyContext: InjectorDependencyContext,
  wrapper: InstanceWrapper<T>,
  resolutionContext: ResolutionContext = { contextId: STATIC_CONTEXT },
  keyOrIndex?: string | number,
): Promise<InstanceWrapper> {
  try {
    const existingProviderWrapper = await super.resolveComponentWrapper(
      moduleRef,
      name,
      dependencyContext,
      wrapper,
      resolutionContext,
      keyOrIndex,
    );
    return existingProviderWrapper;
  } catch (err) {
    return this.mockWrapper(err, moduleRef, name, wrapper);
  }
}

public createNestApplication<T extends INestApplication = INestApplication>(
  serverOrOptions:
    | HttpServer
    | AbstractHttpAdapter
    | NestApplicationOptions
    | undefined,
  options?: NestApplicationOptions,
): T {
  const [httpAdapter, appOptions] = this.isHttpServer(serverOrOptions)
    ? [serverOrOptions, options]
    : [this.createHttpAdapter(), serverOrOptions];

  this.applyLogger(appOptions);
  this.container.setHttpAdapter(httpAdapter);

  const instance = new NestApplication(
    this.container,
    httpAdapter,
    this.applicationConfig,
    this.graphInspector,
    appOptions,
  );
  return this.createAdapterProxy<T>(instance, httpAdapter);
}

public exploreMethodMetadata(
  instancePrototype: object,
  methodName: string,
): MessageMappingProperties | null {
  const callback = instancePrototype[methodName];
  const isMessageMapping = Reflect.getMetadata(
    MESSAGE_MAPPING_METADATA,
    callback,
  );
  if (isUndefined(isMessageMapping)) {
    return null;
  }
  const message = Reflect.getMetadata(MESSAGE_METADATA, callback);
  const isAckHandledManually = this.hasAckDecorator(
    instancePrototype,
    methodName,
  );

  return {
    callback,
    message,
    methodName,
    isAckHandledManually,
  };
}

private createSocketServer<T extends GatewayMetadata>(
  options: T,
  port: number,
): ServerAndEventStreamsHost {
  const adapter = this.applicationConfig.getIoAdapter();
  const { namespace, server, ...partialOptions } = options as Record<
    string,
    unknown
  >;
  const ioServer = adapter.create(port, partialOptions);
  const serverAndEventStreamsHost =
    ServerAndEventStreamsFactory.create(ioServer);

  this.socketsContainer.addOne(
    { port, path: options.path },
    serverAndEventStreamsHost,
  );
  if (!namespace) {
    return serverAndEventStreamsHost;
  }
  return this.decorateWithNamespace(options, port, ioServer);
}

getStatusCodeIdentifier(factory: ts.NodeFactory, node: ts.MethodDeclaration) {
  const decorators = ts.canHaveDecorators(node) && ts.getDecorators(node);
  const httpCodeDecorator = getDecoratorOrUndefinedByNames(
    ['HttpCode'],
    decorators,
    factory
  );
  if (httpCodeDecorator) {
    const argument = head(getDecoratorArguments(httpCodeDecorator));
    if (argument) {
      return argument;
    }
  }
  const postDecorator = getDecoratorOrUndefinedByNames(
    ['Post'],
    decorators,
    factory
  );
  if (postDecorator) {
    return factory.createIdentifier('201');
  }
  return factory.createIdentifier('200');
}

private async pingDb(timeout: number, prismaClientSQLOrMongo: PrismaClient) {
  // The prisma client generates two different typescript types for different databases
  // but inside they've the same methods
  // But they will fail when using a document method on sql database, that's why we do the try catch down below
  const prismaClient = prismaClientSQLOrMongo as PrismaClientSQL &
    PrismaClientDocument;

  try {
    await promiseTimeout(timeout, prismaClient.$runCommandRaw({ ping: 1 }));
  } catch (error) {
    if (
      error instanceof Error &&
      error.toString().includes('Use the mongodb provider')
    ) {
      await promiseTimeout(timeout, prismaClient.$queryRawUnsafe('SELECT 1'));
      return;
    }

    throw error;
  }
}

private async getOrgIdFromSlug(organizationSlug: string): Promise<string | undefined> {
  if (!organizationSlug) {
    this.logger.debug('organizationSlug not found');
    return undefined;
  }

  // this.logger.debug('organizationSlug found', organizationSlug);

  const organization = await this.organizationRepo.findOne({ slug: organizationSlug }, { skipAuthorization: true });
  if (!organization) {
    this.logger.debug('orgId not found for slug', organizationSlug);
    return undefined;
  }

  this.logger.debug('orgId found for slug', {
    organizationSlug,
    orgId: organization.id,
  });
  return organization.id;
}

public async isAuthorized(params: AuthorizationCheckParams<AccessPermissionsEntity, CrudOperations>): Promise<boolean> {
  if (!params.targetResource || !params.targetResource) throw new AppError('target.resource can not be null');

  const scopedParams = {
    accessPermissions: params.accessPermissions,
    origin: params.origin,
    operation: params.operation,
    targetResource: new ScopedData(),
    data: params.data,
  };

  if (params.targetResource.organizations) {
    for (const orgAccess of params.targetResource.organizations) {
      scopedParams.targetResource.orgId = orgAccess.orgId;
      await this.orgAdminAuthCheck.ensureAuthorized(scopedParams);
    }
  }

  // if authorization not already denied, then allow access (return true)
  return true;
}

