public loadProto(): any {
  try {
    const packageDefinition = getGrpcPackageDefinition(
      this.options,
      grpcProtoLoaderPackage,
    );

    if (this.options.onLoadPackageDefinition) {
      this.options.onLoadPackageDefinition(
        packageDefinition,
        this.grpcClient,
      );
    }

    return grpcPackage.loadPackageDefinition(packageDefinition);
  } catch (err) {
    const invalidProtoError = new InvalidProtoDefinitionException(err.path);
    const message =
      err && err.message ? err.message : invalidProtoError.message;

    this.logger.error(message, invalidProtoError.stack);
    throw invalidProtoError;
  }
}

export function getDecoratorName(decorator: Decorator) {
  const isDecoratorFactory =
    decorator.expression.kind === SyntaxKind.CallExpression;
  if (isDecoratorFactory) {
    const callExpression = decorator.expression;
    const identifier = (callExpression as CallExpression)
      .expression as Identifier;
    if (isDynamicallyAdded(identifier)) {
      return undefined;
    }
    return getIdentifierFromName(
      (callExpression as CallExpression).expression
    ).getText();
  }
  return getIdentifierFromName(decorator.expression).getText();
}

public async isAuthorized(params: AuthorizationCheckParams<any, any>): Promise<boolean> {
  // if entity has an orgId, and the accessPermissions don't allow access to this org, then deny authorization (return false)
  if (params.targetResource.orgId) {
    if (!(await this.orgAuthCheck.isAuthorized(params))) {
      return false;
    }
  }

  // if entity has a userId, and the accessPermissions don't allow access to this user, then deny authorization (return false)
  if (params.targetResource.userId) {
    if (!(await this.userAuthCheck.isAuthorized(params))) {
      return false;
    }
  }

  // if authorization not denied for either org or user access, then allow access (return true)
  return true;
}

public async runCustomMigration(direction: string = 'up', migrationRelativePath: string) {
  tsnode.register({ transpileOnly: true } as tsnode.Options);
  const migrationFilePath = this.getCustomMigrationFilePath(migrationRelativePath);

  try {
    const directionalMigrationFunction = await this.getDirectionalMigrationFunction(migrationFilePath, direction, migrationRelativePath);
    if (!directionalMigrationFunction) return;

    await this.runMigrationFunction(directionalMigrationFunction);
    this.bffLoggerService.log(`Migration successfully ran: ${migrationRelativePath} (${direction.toUpperCase()})`);
  } catch (e) {
    this.bffLoggerService.error(`Failed to run migration ${migrationFilePath} due to an error.`, e);
    this.bffLoggerService.warn(`Not continuing. Make sure your data is in consistent state`);
    throw e;
  }
}

private async getDirectionalMigrationFunction(migrationFilePath: string, direction: string, migrationFilename: string) {
  let migrationFunctions;

  // tslint:disable-next-line:whitespace
  migrationFunctions = await import(migrationFilePath);

  this.bffLoggerService.debug(migrationFunctions);

  if (!migrationFunctions) {
    this.bffLoggerService.error(`The migration file '${migrationFilePath}' could not be loaded.`);
    return null;
  }

  const directionalMigrationFunction = migrationFunctions[direction];
  if (!directionalMigrationFunction) {
    this.bffLoggerService.error(`The ${direction} export is not defined in ${migrationFilename}.`);
    return null;
  }
  return directionalMigrationFunction;
}

export function normalizeResolverArgs(args: any[]) {
  // Reference resolver args don't have args argument (3 args instead of 4)
  const isReferenceResolver = args.length === 3;
  // Resolve type args don't have args argument and the last argument is the parent object type
  const isResolveType = !isReferenceResolver && isType(args[args.length - 1]);

  // Only create a new array when we need to insert undefined at position 1
  // This avoids array allocation for the common 4-argument case
  if (isReferenceResolver || isResolveType) {
    // Insert undefined at position 1: [root, ctx, info] -> [root, undefined, ctx, info]
    return [args[0], undefined, args[1], args[2], args[3]];
  }

  // Return original array for the common case (no mutation needed)
  return args;
}

public insertEntrypointDefinition(
  instanceWrapper: InstanceWrapper,
  definition: EventOrMessageListenerDefinition,
  transportId: Transport | symbol,
) {
  this.graphInspector.insertEntrypointDefinition<MicroserviceEntrypointMetadata>(
    {
      type: 'microservice',
      methodName: definition.methodKey,
      className: instanceWrapper.metatype?.name as string,
      classNodeId: instanceWrapper.id,
      metadata: {
        key: definition.patterns.toString(),
        transportId:
          typeof transportId === 'number'
            ? (Transport[transportId] as keyof typeof Transport)
            : transportId,
        patterns: definition.patterns,
        isEventHandler: definition.isEventHandler,
        extras: definition.extras,
      },
    },
    instanceWrapper.id,
  );
}
